const { Client } = require('pg');
const docId = '9d09fa89-3a46-465e-a98b-837287c9e22a';
const route = 'qwen/qwen3-vl-235b-a22b-thinking';
(async () => {
  const client = new Client({ connectionString: process.env.PROD_URL, statement_timeout: 120000 });
  await client.connect();
  try {
    await client.query('begin');
    const url = process.env.PROD_URL || '';
    if (!url.includes('eqccjfbyrywsqkxxpjvg')) throw new Error('ABORT: connection URL is not current prod ref');
    const doc = await client.query('select id from documents where id=$1 for update', [docId]);
    if (doc.rowCount !== 1) throw new Error('ABORT: fixture document not found');
    const settings = await client.query("select key, value from settings where key in ('default_vision_route','model_pool_vision','default_vision_reasoning_effort','enforce_model_capabilities') order by key");
    const settingMap = Object.fromEntries(settings.rows.map(r => [r.key, r.value]));
    const pool = Array.isArray(settingMap.model_pool_vision) ? settingMap.model_pool_vision : [];
    const poolChanged = !pool.includes(route);
    const newPool = poolChanged ? [...pool, route] : pool;
    await client.query("insert into settings(key,value,updated_at) values('default_vision_route', to_jsonb($1::text), now()) on conflict(key) do update set value=excluded.value, updated_at=now()", [route]);
    await client.query("insert into settings(key,value,updated_at) values('model_pool_vision', $1::jsonb, now()) on conflict(key) do update set value=excluded.value, updated_at=now()", [JSON.stringify(newPool)]);

    const ids = await client.query(`with doc_chunks as (select id from document_chunks where document_id=$1), doc_claims as (select distinct ce.claim_id as id from claim_evidence ce join doc_chunks dc on dc.id=ce.source_document_chunk_id where ce.claim_id is not null) select coalesce(array_agg(id), '{}') as claim_ids from doc_claims`, [docId]);
    const chunkIdsRes = await client.query('select coalesce(array_agg(id), $2::uuid[]) as chunk_ids from document_chunks where document_id=$1', [docId, []]);
    const claimIds = ids.rows[0].claim_ids || [];
    const chunkIds = chunkIdsRes.rows[0].chunk_ids || [];
    const counts = { claimIds: claimIds.length, chunkIds: chunkIds.length, poolChanged };
    async function del(name, sql, params) { const r = await client.query(sql, params); counts[name] = r.rowCount; }
    if (claimIds.length) {
      await del('section_claims', 'delete from section_claims where claim_id = any($1::uuid[])', [claimIds]);
      await del('macro_relationship_claims', 'delete from macro_relationship_claims where claim_id = any($1::uuid[])', [claimIds]);
      await del('process_element_claims', 'delete from process_element_claims where claim_id = any($1::uuid[])', [claimIds]);
      await del('source_outline_source_refs_claim', 'delete from source_outline_source_refs where claim_id = any($1::uuid[])', [claimIds]);
      await del('claim_extraction_ab_tests_source', 'delete from claim_extraction_ab_tests where source_claim_id = any($1::uuid[])', [claimIds]);
      await del('claim_extraction_ab_tests_revised', 'delete from claim_extraction_ab_tests where revised_claim_id = any($1::uuid[])', [claimIds]);
      await del('gaps_resolved_by', 'update gaps set resolved_by_claim_id = null where resolved_by_claim_id = any($1::uuid[])', [claimIds]);
      await del('gaps_related_pruned', `update gaps g set related_claim_ids = coalesce((select jsonb_agg(x.v) from jsonb_array_elements_text(g.related_claim_ids) x(v) where not (x.v = any($1::uuid[]::text[]))), '[]'::jsonb) where exists (select 1 from jsonb_array_elements_text(g.related_claim_ids) x(v) where x.v = any($1::uuid[]::text[]))`, [claimIds]);
    }
    if (chunkIds.length) {
      await del('source_outline_source_refs_chunk', 'delete from source_outline_source_refs where document_chunk_id = any($1::uuid[])', [chunkIds]);
      await del('source_group_items', 'delete from source_group_items where document_chunk_id = any($1::uuid[])', [chunkIds]);
    }
    await del('source_workflow_maps_superseded', "update source_workflow_maps set status='superseded', updated_at=now() where source_type='document' and document_id=$1 and status <> 'superseded'", [docId]);
    await client.query('commit');
    console.log(JSON.stringify({ ok: true, run: 'A-qwen-prep', counts, finalRoute: route, pool: newPool }, null, 2));
  } catch (e) { await client.query('rollback'); throw e; }
  finally { await client.end(); }
})().catch(e => { console.error(e); process.exit(1); });
